// App.jsx
import { Routes, Route, Navigate } from "react-router-dom";
import { useState } from "react";
import Register from "./pages/Auth/Register";
import Login from "./pages/Auth/Login";
import Dashboard from "./pages/Dashboard/Dashboard";
import MasterData from "./pages/MasterData/MasterData";

export default function App() {
  const [userRole, setUserRole] = useState(null);
  const isLoggedIn = !!userRole;

  return (
    <Routes>
      <Route path="/admin/register" element={<Register role="Admin" />} />
      <Route path="/admin/login" element={<Login role="Admin" setUserRole={setUserRole} />} />
      <Route path="/superadmin/register" element={<Register role="Super Admin" />} />
      <Route path="/superadmin/login" element={<Login role="Super Admin" setUserRole={setUserRole} />} />

      <Route
        path="/dashboard"
        element={isLoggedIn ? <Dashboard role={userRole} /> : <Navigate to="/admin/login" />}
      />
      <Route
        path="/master-data"
        element={isLoggedIn ? <MasterData role={userRole} /> : <Navigate to="/admin/login" />}
      />

      <Route path="*" element={<Navigate to="/admin/register" />} />
    </Routes>
  );
}
